import React, { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { useNavigate, useParams } from 'react-router-dom';
import { useMutation, useQuery, useQueryClient } from 'react-query';
import axios from 'axios';
import { Save, ArrowLeft, Eye } from 'lucide-react';
import ImageUpload from '../../components/ImageUpload';

const NewsForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const isEdit = !!id;

  const [image, setImage] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [tags, setTags] = useState([]);
  const [tagInput, setTagInput] = useState('');

  const { register, handleSubmit, formState: { errors }, reset, setValue, watch } = useForm();

  // Carregar dados da notícia para edição
  const { data: news } = useQuery(
    ['news', id],
    () => axios.get(`/api/news/admin/${id}`).then(res => res.data),
    { 
      enabled: isEdit,
      onSuccess: (data) => {
        // Preencher formulário
        Object.keys(data).forEach(key => {
          if (key === 'image') {
            setImage(data[key]);
          } else if (key === 'tags') {
            setTags(data[key] || []);
          } else {
            setValue(key, data[key]);
          }
        });
      }
    }
  );

  const mutation = useMutation(
    (data) => {
      if (isEdit) {
        return axios.put(`/api/news/${id}`, data);
      } else {
        return axios.post('/api/news', data);
      }
    },
    {
      onSuccess: () => {
        queryClient.invalidateQueries('news');
        navigate('/admin/noticias');
      }
    }
  );

  const handleImageUpload = async (files) => {
    const formData = new FormData();
    formData.append('image', files[0]);

    try {
      const response = await axios.post('/api/news/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      setImage(response.data.image);
    } catch (error) {
      throw new Error('Erro ao fazer upload da imagem');
    }
  };

  const handleImageRemove = async () => {
    if (image?.path) {
      try {
        await axios.delete(`/api/news/image/${image.path}`);
      } catch (error) {
        console.error('Erro ao remover imagem:', error);
      }
    }
    setImage(null);
  };

  const addTag = () => {
    if (tagInput.trim() && !tags.includes(tagInput.trim())) {
      setTags([...tags, tagInput.trim()]);
      setTagInput('');
    }
  };

  const removeTag = (tagToRemove) => {
    setTags(tags.filter(tag => tag !== tagToRemove));
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      addTag();
    }
  };

  const onSubmit = async (data) => {
    setIsSubmitting(true);
    try {
      const submitData = {
        ...data,
        image: image,
        tags: tags
      };
      await mutation.mutateAsync(submitData);
    } catch (error) {
      alert('Erro ao salvar notícia');
    } finally {
      setIsSubmitting(false);
    }
  };

  const title = watch('title');
  const content = watch('content');

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="mb-8">
        <button
          onClick={() => navigate('/admin/noticias')}
          className="inline-flex items-center text-primary-600 hover:text-primary-700 mb-4"
        >
          <ArrowLeft className="h-4 w-4 mr-2" />
          Voltar às Notícias
        </button>
        <h1 className="text-3xl font-bold text-gray-900">
          {isEdit ? 'Editar Notícia' : 'Criar Nova Notícia'}
        </h1>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Formulário */}
        <div className="lg:col-span-2">
          <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
            {/* Informações Básicas */}
            <div className="bg-white rounded-lg shadow-md p-6">
              <h2 className="text-xl font-semibold text-gray-900 mb-6">
                Informações da Notícia
              </h2>

              <div className="space-y-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Título *
                  </label>
                  <input
                    type="text"
                    {...register('title', { required: 'Título é obrigatório' })}
                    className="input-field"
                    placeholder="Título da notícia"
                  />
                  {errors.title && (
                    <p className="text-red-600 text-sm mt-1">{errors.title.message}</p>
                  )}
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Resumo *
                  </label>
                  <textarea
                    {...register('excerpt', { required: 'Resumo é obrigatório' })}
                    rows="3"
                    className="input-field"
                    placeholder="Breve resumo da notícia (será exibido na listagem)"
                  />
                  {errors.excerpt && (
                    <p className="text-red-600 text-sm mt-1">{errors.excerpt.message}</p>
                  )}
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Conteúdo *
                  </label>
                  <textarea
                    {...register('content', { required: 'Conteúdo é obrigatório' })}
                    rows="12"
                    className="input-field"
                    placeholder="Conteúdo completo da notícia..."
                  />
                  {errors.content && (
                    <p className="text-red-600 text-sm mt-1">{errors.content.message}</p>
                  )}
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Status
                  </label>
                  <select {...register('status')} className="input-field">
                    - <option value="draft">Rascunho</option>
        - <option value="published">Publicado</option>
      + <option value="rascunho">Rascunho</option>
        + <option value="publicado">Publicado</option>
                  </select>
                </div>
              </div>
            </div>

            {/* Tags */}
            <div className="bg-white rounded-lg shadow-md p-6">
              <h2 className="text-xl font-semibold text-gray-900 mb-6">
                Tags
              </h2>

              <div className="space-y-4">
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={tagInput}
                    onChange={(e) => setTagInput(e.target.value)}
                    onKeyPress={handleKeyPress}
                    className="input-field flex-1"
                    placeholder="Digite uma tag e pressione Enter"
                  />
                  <button
                    type="button"
                    onClick={addTag}
                    className="btn-outline"
                  >
                    Adicionar
                  </button>
                </div>

                {tags.length > 0 && (
                  <div className="flex flex-wrap gap-2">
                    {tags.map((tag, index) => (
                      <span
                        key={index}
                        className="inline-flex items-center px-3 py-1 bg-primary-100 text-primary-700 rounded-full text-sm"
                      >
                        {tag}
                        <button
                          type="button"
                          onClick={() => removeTag(tag)}
                          className="ml-2 text-primary-500 hover:text-primary-700"
                        >
                          ×
                        </button>
                      </span>
                    ))}
                  </div>
                )}
              </div>
            </div>

            {/* Imagem */}
            <div className="bg-white rounded-lg shadow-md p-6">
              <h2 className="text-xl font-semibold text-gray-900 mb-6">
                Imagem de Destaque
              </h2>

              <ImageUpload
                onUpload={handleImageUpload}
                existingImages={image ? [image] : []}
                onRemove={handleImageRemove}
                multiple={false}
                maxFiles={1}
              />
            </div>

            {/* Botões */}
            <div className="flex justify-end space-x-4">
              <button
                type="button"
                onClick={() => navigate('/admin/noticias')}
                className="btn-outline"
              >
                Cancelar
              </button>
              <button
                type="submit"
                disabled={isSubmitting}
                className="btn-primary flex items-center disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isSubmitting ? (
                  <>
                    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                    Salvando...
                  </>
                ) : (
                  <>
                    <Save className="h-4 w-4 mr-2" />
                    {isEdit ? 'Atualizar' : 'Publicar'}
                  </>
                )}
              </button>
            </div>
          </form>
        </div>

        {/* Preview */}
        <div className="lg:col-span-1">
          <div className="bg-white rounded-lg shadow-md p-6 sticky top-8">
            <div className="flex items-center mb-4">
              <Eye className="h-5 w-5 text-gray-400 mr-2" />
              <h3 className="text-lg font-semibold text-gray-900">Preview</h3>
            </div>

            <div className="space-y-4">
              {image && (
                <img
                  src={`/uploads/${image.path}`}
                  alt="Preview"
                  className="w-full h-32 object-cover rounded-lg"
                />
              )}

              {title && (
                <h4 className="font-semibold text-gray-900 line-clamp-2">
                  {title}
                </h4>
              )}

              {content && (
                <p className="text-sm text-gray-600 line-clamp-4">
                  {content.substring(0, 150)}...
                </p>
              )}

              {tags.length > 0 && (
                <div className="flex flex-wrap gap-1">
                  {tags.slice(0, 3).map((tag, index) => (
                    <span
                      key={index}
                      className="px-2 py-1 bg-gray-100 text-gray-600 rounded text-xs"
                    >
                      {tag}
                    </span>
                  ))}
                  {tags.length > 3 && (
                    <span className="px-2 py-1 bg-gray-100 text-gray-600 rounded text-xs">
                      +{tags.length - 3}
                    </span>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default NewsForm;
